FROM jsonb_to_recordset('[{"id": "cap-112-chinese-passage-25", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下詩作，並回答25 ～ 26題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下詩作，並回答25 ～ 26題：", "child_qnums": [25, 26]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-passage-27", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "reading_passage", "question_text": "以下圖文改寫自亞當．斯金納《運動大百科》，請閱讀並回答27 ～ 29題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "以下圖文改寫自亞當．斯金納《運動大百科》，請閱讀並回答27 ～ 29題：", "child_qnums": [27, 28, 29]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-passage-30", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下短文，並回答30 ～ 31題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "寒假期間的圖書館，呈現一種難得的閒逸姿態。這一棟半圓形的八層樓建築，\n環壁皆書，中間留下跟應用坪數相等的半圓形空間。從五樓俯望，偌大的建築顯得\n十分空洞。陰冷盤踞了多餘的空間，恍如進入一座潔淨，但森冷的納骨塔。整齊有\n序的書本，宛如一個個編號的骨灰罈，罈子裡都裝載著作者的魂。也許讀書的心都\n冬眠去了，這些思考宇宙大道，辯解生命本質的沉重書魂，都顯得有些黯然。\n我通過文字開啟深邃寬廣的知識世界，同時釋放囚在罈子裡的書魂。我們的交\n談安靜而無聲。這種滅音的交談沒有負擔，對方的想法不盡完善，就在架上搜尋互\n為補強的觀點，讓不同意見的寄魂去辯駁。年輕的書魂總是按捺不住脾氣，氣勢凌\n厲且偏激；老書魂則不動如山，總能敗部復活，在逆境裡扭轉乾坤。讀書比看戲更\n令人著迷，難怪有不少讀者活著的時候就心甘情願把自己埋進納骨塔，想來精彩的\n書還真有勾魂攝魄的魅力。\n—— 改寫自鍾怡雯〈藏魂〉", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下短文，並回答30 ～ 31題：", "child_qnums": [30, 31]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-passage-34", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下短文，並回答34 ～ 35題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "「隱私」是一種多元流動的概念，窗簾代表一種隱私，提款卡密碼是一種\n隱私，筆電防窺貼片是一種隱私。在我讀高中的年代，「隱私」意謂著上鎖的日記\n本、父母進房間前先敲門。\n如今在網路上，瀏覽紀錄、按讚喜好、地理位置、基本個資等這些看不到的\n數據，都是商業可變現、政治可操縱的黑箱資料。\n以往，我們常嘲笑將網站密碼設為「1234」或自己生日的朋友，然而，真實\n世界更幽微：\n你是否知道，Google的智慧音箱、臉書的語音通話，都被他們錄下來，並交由\n人力聽取並抄錄，理由是「優化人工智慧」？\n你是否知道，YouTube因未經監護人同意，違法蒐集兒童隱私，被美國政府\n重罰？\n你是否知道，看似無關隱私的掃地機器人龍頭iRobot，執行長一度動念將機器\n人蒐集的用戶住家平面圖出售作為「智慧家庭」的數據資料庫，後因輿論反彈才\n作罷？\n這些例子，說明數位時代「隱私」的高度複雜性，更別提，我們點閱特定產\n品網頁後，不管逛到哪個網站，同一產品廣告如影隨形。未來可能無論我們走到哪\n裡，戶外廣告牆會自動掃描每個人的眼球，播放符合個人興趣特徵的廣告。\n關於網路隱私，當前最重要的挑戰是，當我們同意使用某一網路服務，形同\n自願交出私密資料。然而，我們完全不知道，誰可能取得這些資料，又會用在哪些\n地方？\n—— 改寫自黃哲斌〈個資可以吃嗎？給現代公民的網路隱私守則〉", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下短文，並回答34 ～ 35題：", "child_qnums": [34, 35]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-passage-36", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下短文，並回答36 ～ 38題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "名畫〈拿破崙的加冕禮〉現藏於羅浮宮，由首席宮廷繪師雅克路易．大衛在加\n冕禮隔年開始起草，約兩年多完成。\n過去25代的法國國王都在巴黎東北方的蘭斯聖母院大教堂加冕。但拿破崙不願\n意被當成波旁王朝的繼承者，而自稱為「法國人的皇帝」，因此拒絕在蘭斯加冕，選\n擇在巴黎聖母院舉行加冕。同時仿效一千多年前的「羅馬人的皇帝」查理曼大帝，\n由羅馬教皇庇護七世主持，而不是蘭斯大主教。\n當年查理曼大帝都還是親自前往梵蒂岡，拿破崙卻要求教皇至巴黎主持加冕典\n禮。在大典開始前，拿破崙已經身著絳紅色皇袍，頭戴金質羅馬式的桂冠，手持權\n杖，且未等教皇拿祭壇上的皇冠，就自己戴上，接著又親手為皇后約瑟芬授冠。但\n對教會如此傲慢的態度，若如實畫出，真的好嗎？因此大衛決定採用皇帝給皇后加\n冕的畫面，而不談誰為拿破崙加冕。\n畫面的正中央是代表神權的十字架。從十字架、拿破崙、教皇由高到低的位\n置可看出拿破崙成了領軍人物，他跳過了代理神權的教會中介，直接實現了君權神\n授的完美結合。畫中拿破崙替皇后約瑟芬加冕，教皇庇護七世坐在拿破崙身後，面\n色凝重，但從教皇舉起的右手，還是可看出他正在為這一場面祝福。但這畫面仍有\n大衛虛構之處：當時拿破崙的母親根本沒有出席，也一併被畫在畫作裡。後來成為\n法國皇太后的她十分反對加冕典禮，擔憂兒子稱帝後將引發許多恐怖之事，因此遠\n走米蘭，在典禮結束後才回巴黎，將皇太后放入畫中是拿破崙本人提出的要求。至\n於畫作主角拿破崙，畫裡的他成了體型瘦高的男子，這自然是為了迎合身型矮小的\n拿破崙的虛榮心，好宣揚其驍勇善戰的英勇姿態，及帝王居高臨下、無人能左右的\n威權。\n—— 改寫自中野京子《療癒羅浮宮》", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下短文，並回答36 ～ 38題：", "child_qnums": [36, 37, 38]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-passage-39", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下短文，並回答39 ～ 40題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "大將軍仇鸞，始為曾銑所劾，欲倚嚴嵩以抗曾銑，故約為父子。已而鸞得帝\n重，嵩猶視之若子，遂浸相惡。嵩密疏毀鸞，帝不聽，而頗納鸞所陳嵩父子過，少\n疏之。嵩當入值，不召者數矣。嵩見徐階、李本入西內1，即與俱入。至西華門，\n門者以非詔旨格之。嵩還第，父子對泣。時陸炳掌錦衣，與鸞爭寵，嵩乃結炳共圖\n鸞。會鸞病死，炳訐鸞陰事，帝追戮之。於是益信任嵩，遣所乘龍舟過海子召嵩，\n載值西內如故。\n—— 改寫自《明史．奸臣》\n", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下短文，並回答39 ～ 40題：", "child_qnums": [39, 40]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-passage-41", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下短文，並回答41 ～ 42題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "楊朱見梁王，言治天下如運諸掌。梁王曰：「先生有三畝之園而不能耘，而言\n治天下如運諸掌，何也？」對曰：「君不見牧羊者乎？百羊而群，使五尺童子荷杖\n隨之，欲東而東，欲西而西。使堯牽一羊，舜荷杖隨之，則不能前矣。且臣聞之：\n吞舟之魚，不游支流；鴻鵠高飛，不集汙池。何則？其志遠也。黃鐘大呂不可從繁\n奏之舞。何則？其音疏也。將治大者不治細，成大功者不成小，此之謂矣。」\n—— 改寫自《列子．楊朱》", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下短文，並回答41 ～ 42題：", "child_qnums": [41, 42]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
